//! # Grids — the Mutable Instruments topographic drum sequencer
//!
//! Ported from pichenettes/eurorack (grids/pattern_generator.cc, MIT,
//! copyright 2011 Emilie Gillet, attribution preserved): the 5×5 drum
//! map with bilinear interpolation between nodes (the 25 node tables
//! extracted verbatim to grids_nodes.bin), per-part randomness
//! perturbation, density thresholds, accents above 192, and the
//! euclidean mode's Bjorklund table generated by the same algorithm
//! as resources/lookup_tables.py.
//!
//! In los grids is a NOTE SOURCE: it follows the transport (8 steps
//! per beat, 32-step patterns) and emits kick/snare/hat note events
//! on `grids/N/bd·sd·hh` — bind a peaks channel or any voice to them.
//! The three trigger levels and the accent also publish on the
//! modulation bus.

use std::io;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, Instant};

use anyhow::Result;
use crossterm::{
    event::{self, EnableMouseCapture, Event, KeyCode, KeyModifiers, MouseEventKind},
    execute,
    terminal::{enable_raw_mode, EnterAlternateScreen},
};
use ratatui::{
    backend::CrosstermBackend,
    style::Style,
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph},
    Terminal,
};

use crate::routing::{self, SourceAddr};
